data.html:
{% set company_logo = '/files/3bm-logo.png' %}
{% set company_name = '3BM Bouwtechniek V.O.F.' %}
{% set company_address = 'Energieweg 3' %}
{% set company_postal = '4231 DJ Meerkerk' %}
{% set company_phone = '0183 - 35 43 43' %}
{% set company_email = 'info@3bm.nl' %}
{% set company_web = 'www.3bm.nl' %}

<style>
@page {
    size: A4;
    margin: 0;
}

@media print {
    .page-break {
        page-break-after: always;
    }
}

body {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    font-size: 10pt;
    color: #333;
    margin: 0;
    padding: 0;
}

.cover-page {
    height: 297mm;
    width: 210mm;
    position: relative;
    background: linear-gradient(135deg, #1a365d 0%, #2d5a87 100%);
    color: white;
    display: flex;
    flex-direction: column;
}

.cover-header {
    padding: 20mm 15mm;
    text-align: right;
}

.cover-logo {
    height: 25mm;
}

.cover-image-container {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 10mm 20mm;
}

.cover-image {
    max-width: 100%;
    max-height: 120mm;
    object-fit: contain;
    border-radius: 4px;
    box-shadow: 0 4px 20px rgba(0,0,0,0.3);
}

.cover-title-section {
    background: rgba(255,255,255,0.95);
    color: #1a365d;
    padding: 15mm 20mm;
    margin: 0 15mm 20mm 15mm;
    border-radius: 4px;
}

.cover-title {
    font-size: 24pt;
    font-weight: 700;
    margin: 0 0 5mm 0;
    line-height: 1.2;
}

.cover-subtitle {
    font-size: 12pt;
    color: #666;
    margin: 0;
}

.cover-doc-id {
    font-size: 10pt;
    color: #888;
    margin-top: 3mm;
}

.details-page {
    height: 297mm;
    width: 210mm;
    padding: 20mm;
    box-sizing: border-box;
    position: relative;
}

.details-header {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    margin-bottom: 15mm;
    padding-bottom: 5mm;
    border-bottom: 2px solid #1a365d;
}

.details-logo {
    height: 15mm;
}

.details-title {
    font-size: 18pt;
    color: #1a365d;
    font-weight: 700;
}

.details-table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 10mm;
}

.details-table th {
    background: #1a365d;
    color: white;
    padding: 3mm 5mm;
    text-align: left;
    font-weight: 600;
    font-size: 11pt;
}

.details-table td {
    padding: 3mm 5mm;
    border-bottom: 1px solid #ddd;
    vertical-align: top;
}

.details-table tr:nth-child(even) {
    background: #f8f9fa;
}

.details-table .label {
    width: 40%;
    font-weight: 600;
    color: #1a365d;
}

.details-table .value {
    width: 60%;
}

.revision-section {
    margin-top: 10mm;
}

.revision-title {
    font-size: 12pt;
    font-weight: 700;
    color: #1a365d;
    margin-bottom: 3mm;
}

.revision-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 9pt;
}

.revision-table th {
    background: #e9ecef;
    padding: 2mm 3mm;
    text-align: left;
    border: 1px solid #dee2e6;
}

.revision-table td {
    padding: 2mm 3mm;
    border: 1px solid #dee2e6;
}

.toc-page {
    height: 297mm;
    width: 210mm;
    padding: 20mm;
    box-sizing: border-box;
}

.toc-header {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    margin-bottom: 10mm;
    padding-bottom: 5mm;
    border-bottom: 2px solid #1a365d;
}

.toc-title {
    font-size: 18pt;
    color: #1a365d;
    font-weight: 700;
    margin-bottom: 10mm;
}

.toc-list {
    list-style: none;
    padding: 0;
    margin: 0;
}

.toc-item {
    display: flex;
    justify-content: space-between;
    padding: 2mm 0;
    border-bottom: 1px dotted #ccc;
}

.toc-item-title {
    flex: 1;
}

.toc-item-page {
    width: 20mm;
    text-align: right;
    color: #666;
}

.back-cover {
    height: 297mm;
    width: 210mm;
    background: #1a365d;
    color: white;
    display: flex;
    flex-direction: column;
    justify-content: flex-end;
    align-items: center;
    padding-bottom: 40mm;
}

.back-logo {
    height: 30mm;
    margin-bottom: 10mm;
}

.back-contact {
    text-align: center;
    font-size: 10pt;
    line-height: 1.6;
}

.page-footer {
    position: absolute;
    bottom: 10mm;
    left: 20mm;
    right: 20mm;
    display: flex;
    justify-content: space-between;
    font-size: 8pt;
    color: #888;
    border-top: 1px solid #ddd;
    padding-top: 3mm;
}
</style>

<!-- COVER PAGE -->
<div class="cover-page">
    <div class="cover-header">
        <img src="{{ company_logo }}" alt="{{ company_name }}" class="cover-logo" onerror="this.style.display='none'">
    </div>

    <div class="cover-image-container">
        {% if doc.cover_image %}
        <img src="{{ doc.cover_image }}" alt="Project Image" class="cover-image">
        {% else %}
        <div style="width: 150mm; height: 100mm; background: rgba(255,255,255,0.1); border-radius: 4px; display: flex; align-items: center; justify-content: center; color: rgba(255,255,255,0.5);">
            Project Image
        </div>
        {% endif %}
    </div>

    <div class="cover-title-section">
        <h1 class="cover-title">{{ doc.title }}</h1>
        {% if doc.project %}
        <p class="cover-subtitle">Project: {{ doc.project }}</p>
        {% endif %}
        <p class="cover-doc-id">{{ doc.name }} | {{ frappe.format_date(doc.report_date) }}</p>
    </div>
</div>

<div class="page-break"></div>

<!-- PROJECT DETAILS PAGE -->
<div class="details-page">
    <div class="details-header">
        <div class="details-title">Project Details</div>
        <img src="{{ company_logo }}" alt="{{ company_name }}" class="details-logo" onerror="this.style.display='none'">
    </div>

    <table class="details-table">
        <tr>
            <th colspan="2">Document Information</th>
        </tr>
        <tr>
            <td class="label">Project</td>
            <td class="value">{{ doc.title or '-' }}</td>
        </tr>
        <tr>
            <td class="label">Customer (In opdracht van)</td>
            <td class="value">{{ doc.customer or '-' }}<br>{{ (doc.customer_address or '') | replace('\n', '<br>') | safe }}</td>
        </tr>
        <tr>
            <td class="label">Author (Auteur)</td>
            <td class="value">{{ doc.author or '-' }}</td>
        </tr>
        <tr>
            <td class="label">Internal Control (Interne controle)</td>
            <td class="value">{{ doc.internal_control or '-' }}</td>
        </tr>
        <tr>
            <td class="label">Applied Norms (Toegepaste Normen)</td>
            <td class="value">{{ (doc.applied_norms or '-') | replace('\n', '<br>') | safe }}</td>
        </tr>
        <tr>
            <td class="label">Document Details (Documentgegevens)</td>
            <td class="value">{{ doc.document_details or '-' }}</td>
        </tr>
        <tr>
            <td class="label">Report Date (Datum rapport)</td>
            <td class="value">{{ frappe.format_date(doc.report_date) }}</td>
        </tr>
        <tr>
            <td class="label">Phase (Fase in bouwproces)</td>
            <td class="value">{{ doc.phase or '-' }}</td>
        </tr>
        <tr>
            <td class="label">Status (Rapportstatus)</td>
            <td class="value">{{ doc.status or '-' }}</td>
        </tr>
        <tr>
            <td class="label">Document ID (Documentkenmerk)</td>
            <td class="value">{{ doc.name }}</td>
        </tr>
    </table>

    {% if doc.revisions %}
    <div class="revision-section">
        <div class="revision-title">Revision History</div>
        <table class="revision-table">
            <tr>
                <th style="width: 15%;">Revision</th>
                <th style="width: 20%;">Date</th>
                <th style="width: 45%;">Description</th>
                <th style="width: 20%;">Author</th>
            </tr>
            {% for rev in doc.revisions %}
            <tr>
                <td>{{ rev.revision }}</td>
                <td>{{ frappe.format_date(rev.date) }}</td>
                <td>{{ rev.description or '-' }}</td>
                <td>{{ rev.author or '-' }}</td>
            </tr>
            {% endfor %}
        </table>
    </div>
    {% endif %}

    <div class="page-footer">
        <span>{{ company_name }}</span>
        <span>{{ doc.name }}</span>
    </div>
</div>

<div class="page-break"></div>

<!-- TABLE OF CONTENTS -->
<div class="toc-page">
    <div class="toc-header">
        <div class="details-title">Table of Contents</div>
        <img src="{{ company_logo }}" alt="{{ company_name }}" class="details-logo" onerror="this.style.display='none'">
    </div>

    <h2 class="toc-title">Contents</h2>

    <ul class="toc-list">
        <li class="toc-item">
            <span class="toc-item-title">1. Project Details</span>
            <span class="toc-item-page">2</span>
        </li>
        <li class="toc-item">
            <span class="toc-item-title">2. Table of Contents</span>
            <span class="toc-item-page">3</span>
        </li>
        {% set page_num = 4 %}
        {% for item in doc.items %}
        {% if item.include_in_report %}
        <li class="toc-item">
            <span class="toc-item-title">{{ loop.index + 2 }}. {{ item.title }}</span>
            <span class="toc-item-page">{{ page_num }}</span>
        </li>
        {% set page_num = page_num + 1 %}
        {% endif %}
        {% endfor %}
    </ul>

    <div class="page-footer">
        <span>{{ company_name }}</span>
        <span>{{ doc.name }}</span>
    </div>
</div>

<div class="page-break"></div>

<!-- BACK COVER -->
<div class="back-cover">
    <img src="{{ company_logo }}" alt="{{ company_name }}" class="back-logo" onerror="this.style.display='none'">
    <div class="back-contact">
        <strong>{{ company_name }}</strong><br>
        {{ company_address }}<br>
        {{ company_postal }}<br><br>
        T: {{ company_phone }}<br>
        E: {{ company_email }}<br>
        W: {{ company_web }}
    </div>
</div>
